Thanks for taking the time to report this.

Can you please attach an example that shows the issue or missing feature?  (Must be openly licensed, completely self-contained so can directly run what you provide. Ideally use test_regress format, see https://veripool.org/guide/latest/contributing.html?highlight=test_regress#reporting-bugs)

```
module pipe_id_match #(
  parameter int unsigned     N_STAGES    = 4,           // must be > 0
  parameter int unsigned     N_STAGE_IDS = 2,           // must be > 0
  parameter type             ID_T        = logic[1:0],
  parameter type             DATA_T      = logic[31:0],
  parameter ID_T             STAGE_IDS[N_STAGES-1:0][N_STAGE_IDS-1:0]
) (
  input  logic                clk,
  input  logic                rst_n,
  input  logic                in_v,
  input  ID_T                 in_id,
  input  DATA_T               in_data,
  output logic [N_STAGES-1:0] out_v,
  output ID_T                 out_id  [N_STAGES-1:0],
  output DATA_T               out_data[N_STAGES-1:0]
);
   logic [N_STAGES-1:0]    stage_v;
   logic [N_STAGES*N_STAGE_IDS-1:0] match_id0;

   generate
      for (genvar j=0; j<N_STAGES; j++)
for (genvar k=0; k<N_STAGE_IDS; k++)
  assign match_id0[j*N_STAGE_IDS + k] = in_id == STAGE_IDS[j][k];
   endgenerate
   generate
      for (genvar i=1; i < N_STAGES; i++) begin : g_stg
logic [(N_STAGES-i)*N_STAGE_IDS-1:0] match_id; // flattened
for (genvar j=i; j < N_STAGES; j++)
  for (genvar k=0; k < N_STAGE_IDS; k++) begin
     assign match_id[(j-i)*N_STAGE_IDS + k] = out_id[i-1] == STAGE_IDS[j][k];
  end
      end // block: g_stg
   endgenerate
endmodule // tree_pipe
module tree_connect #(
  parameter int unsigned   N_IDS           = 16,         // must be even, > 0
  parameter int unsigned   N_IDS_PER_STAGE = 2,          // must be > 0
  parameter type           ID_T            = logic[3:0],
  parameter type           DATA_T          = logic[31:0],
  parameter ID_T           SRC_ID                        // must be < N_IDS
) (
  input  logic             clk,
  input  logic             rst_n,
  input  logic             in_v,
  input  ID_T              in_id,
  input  DATA_T            in_data,
  output logic             out_v   [N_IDS-1:0],
  output ID_T              out_id  [N_IDS-1:0],
  output DATA_T            out_data[N_IDS-1:0]
);

   localparam int unsigned N_STAGES = (N_IDS / 2) / N_IDS_PER_STAGE;

   function automatic ID_T[N_STAGES-1:0][N_IDS_PER_STAGE-1:0] gen_stage_ids ();
      for (int unsigned st=0; st < N_STAGES; st++) begin
for (int unsigned id=0; id < N_IDS_PER_STAGE; id++) begin
   gen_stage_ids[st][id] = SRC_ID + ((st+1)*N_IDS_PER_STAGE) + id -
          (SRC_ID + ((st+1)*N_IDS_PER_STAGE) + id <  N_IDS ? 0 :
                                                             N_IDS);
end
      end
   endfunction

   localparam ID_T      STAGE_IDS[N_STAGES-1:0][N_IDS_PER_STAGE-1:0] = gen_stage_ids();

   logic [N_STAGES-1:0] stage_out_v;
   ID_T                 stage_out_id  [N_STAGES-1:0];
   DATA_T               stage_out_data[N_STAGES-1:0];

   pipe_id_match #(
      .N_STAGES   ( N_STAGES ),
      .N_STAGE_IDS( N_IDS_PER_STAGE ),
      .ID_T       ( ID_T ),
      .DATA_T     ( DATA_T ),
      .STAGE_IDS  ( STAGE_IDS )
   ) pipe ( .out_v   ( stage_out_v ),
   .out_id  ( stage_out_id ),
   .out_data( stage_out_data ),
   .* );
endmodule
module tb_tree_connect;
   localparam int N_IDS           = 18;
   localparam int N_IDS_PER_STAGE = 2;
   localparam int ID_W            = 5;

   typedef logic [31:0]     data_t;
   typedef logic [ID_W-1:0] id_t;

   localparam id_t SRC_ID = id_t'(3);

   logic    clk, rst_n;

   logic  in_v;
   id_t   in_id;
   data_t in_data;

   logic  out_v   [N_IDS-1:0];
   id_t   out_id  [N_IDS-1:0];
   data_t out_data[N_IDS-1:0];

   tree_connect #(
      .N_IDS          ( N_IDS ),
      .N_IDS_PER_STAGE( N_IDS_PER_STAGE ),
      .ID_T           ( id_t ),
      .DATA_T         ( data_t ),
      .SRC_ID      ( SRC_ID )
   ) dut ( .* );

endmodule
```

What output from that test indicates it is wrong, and what is the correct or expected output?  (Or, please make test self-checking if possible.)

